        ],
      },
      defaultValue: 'No',
      requiredField: true,
    },
    {
      fieldLabel: 'Iteration to restore',
      fieldName: 'Iteration to restore',
      fieldType: 'dropdown',
      fieldOptions: {
        values: restoreChoices,
      },
    },
    {
      fieldLabel: 'Attachments (optional)',
      fieldName: 'Attachments',
      fieldType: 'file',
    },
    {
      fieldLabel: 'Feedback',
      fieldName: 'Feedback',
      fieldType: 'textarea',
      placeholder: 'Describe exactly what should change in the frontend package.',
    },
  ];

  const descriptionHtml = [
    '<p>Review the current Frontend ZIP, then approve it or request changes.</p>',
    currentDownloadHtml,
    restoreError ? `<p><strong>${escapeHtml(restoreError)}</strong></p>` : '',
    '<p>If you want to return to a previously generated version, choose Yes in Restore older iteration. You can also download any generated iteration below.</p>',
    historyItemsHtml ? `<p>Generated iterations:</p><ol>${historyItemsHtml}</ol>` : '<p>No generated iterations are available yet.</p>',
  ].filter(Boolean).join('');

  return {
    descriptionHtml,
    formJson: JSON.stringify(formFields),
  };
};

const selectionLabel = String(json['Iteration to restore'] ?? '').trim();
const selectionMatch = selectionLabel.match(/Iteration\s+(\d+)/i);
const selectedIterationNumber = selectionMatch ? Number.parseInt(selectionMatch[1], 10) : Number.NaN;
const currentIterationNumber = Number(json.currentFrontendIterationNumber ?? 0) || 0;
const selectedEntry = history.find((entry) => Number(entry.iterationNumber ?? 0) === selectedIterationNumber);

if (selectedEntry && Number(selectedEntry.iterationNumber ?? 0) !== currentIterationNumber) {
  json.frontendStructure = String(selectedEntry.frontendStructure ?? selectedEntry.response ?? json.frontendStructure ?? json.response ?? '').trim();
  json.response = json.frontendStructure;
  json.fileCount = Number(selectedEntry.fileCount ?? json.fileCount ?? 0) || 0;
  json.files = Array.isArray(selectedEntry.files) ? selectedEntry.files : (Array.isArray(json.files) ? json.files : []);
  json.revisionNumber = Number(selectedEntry.revisionNumber ?? json.revisionNumber ?? 0) || 0;
  json.zipDownloadUrl = String(selectedEntry.zipDownloadUrl ?? json.zipDownloadUrl ?? '').trim();
  json.zipDownloadToken = String(selectedEntry.zipDownloadToken ?? json.zipDownloadToken ?? '').trim();
  json.downloadLinkHtml = String(selectedEntry.downloadLinkHtml ?? json.downloadLinkHtml ?? '').trim();
  json.currentFrontendIterationNumber = Number(selectedEntry.iterationNumber ?? json.currentFrontendIterationNumber ?? 0) || 0;
  json.fileCount = Number(selectedEntry.fileCount ?? json.fileCount ?? 0) || 0;
  json.files = Array.isArray(selectedEntry.files) ? selectedEntry.files : (Array.isArray(json.files) ? json.files : []);

  const binaryPropertyName = String(selectedEntry.binaryPropertyName ?? '').trim();
  if (binaryPropertyName && binary[binaryPropertyName]) {
    binary.frontendZip = binary[binaryPropertyName];
  }

  delete json.restoreSelectionError;
} else {
  json.restoreSelectionError = 'Select one of the previously generated iterations to restore it.';
}

const reviewAssets = buildFrontendReviewAssets({
  history,
  currentIterationNumber: Number(json.currentFrontendIterationNumber ?? 0) || 0,
  currentZipDownloadUrl: json.zipDownloadUrl,
  restoreError: String(json.restoreSelectionError ?? '').trim(),
});
json.frontendReviewDescriptionHtml = reviewAssets.descriptionHtml;
json.frontendReviewFormJson = reviewAssets.formJson;

delete json.frontendHistoryHtml;
delete json.reviewMode;
delete json.feedback;
delete json.Feedback;
delete json.Approved;
delete json.Attachments;
delete json['Restore older iteration'];
delete json['Iteration to restore'];

const preservedBinary = {};
for (const [name, value] of Object.entries(binary)) {
  if (name === 'requirements' || name === 'openapiSpec' || name === 'frontendZip' || /^frontend_iteration_\d+$/.test(name)) {
    preservedBinary[name] = value;
  }
}

return [{
  json,
  ...(Object.keys(preservedBinary).length ? { binary: preservedBinary } : {}),
}];

const item = $input.first() ?? { json: {}, binary: {} };
return [{
  json: {
    ...(item.json ?? {}),
    reviewMode: 'refine',
  },
  ...(item.binary && Object.keys(item.binary).length ? { binary: item.binary } : {}),
}];

const item = $input.first() ?? { json: {}, binary: {} };
const json = { ...(item.json ?? {}) };
const binary = { ...(item.binary ?? {}) };

const currentIterationNumber = Number(json.currentFrontendIterationNumber ?? 0) || 0;
const history = Array.isArray(json.frontendHistory)
  ? json.frontendHistory.filter((entry) => entry && typeof entry === 'object')
  : [];

let frontendZip = binary.frontendZip || binary.reviewZip;

if (currentIterationNumber > 0 && history.length > 0) {
  const currentEntry = history.find(
    (entry) => (Number(entry.iterationNumber ?? 0) || 0) === currentIterationNumber,
  );
  const binaryPropertyName = String(currentEntry?.binaryPropertyName ?? '').trim();
  if (binaryPropertyName && binary[binaryPropertyName]) {
    frontendZip = binary[binaryPropertyName];
  }
}

if (!frontendZip) {
  throw new Error('Approved frontend ZIP is missing.');
}

return [{
  json: {
    revisionNumber: Number(json.revisionNumber ?? 0) || 0,
    fileCount: Number(json.fileCount ?? 0) || 0,
    zipDownloadUrl: String(json.zipDownloadUrl ?? '').trim(),
    zipDownloadToken: String(json.zipDownloadToken ?? '').trim(),
    currentFrontendIterationNumber: currentIterationNumber,
  },
  binary: {
    frontendZip,
  },
}];
